#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
typedef long long ll;const int INF=0x3f3f3f3f;
const int N=1e5+10;int a[N],n;bool flag=0;
int fl[35][N],fr[35][N],mn[35][18][N],mx[35][18][N],Lg[N];
inline void Init(int x)
{
	rep(1,17,j)rep(1,n-(1<<j),i)
	{
		mx[x][j][i]=max(mx[x][j-1][i],mx[x][j-1][i+(1<<(j-1))]);
		mn[x][j][i]=min(mn[x][j-1][i],mn[x][j-1][i+(1<<(j-1))]);
	}
}
inline int qmx(int i,int l,int r)
{
	if(l>r)return a[l];int len=Lg[r-l+1];
	return max(mx[i][len][l],mx[i][len][r-(1<<len)+1]);
}
inline int qmn(int i,int l,int r)
{
	if(l>r)return a[l];const int &len=Lg[r-l+1];
	return min(mn[i][len][l],mn[i][len][r-(1<<len)+1]);
}
int main()
{
//	FIN("data.in");
//	FOUT("mine.out");
	n=read();int Q=read();rep(1,n,i)a[i]=read();
	bool f1=0;rep(1,n,i)if(a[i]==1){f1=true;break;}
	bool fn=0;rep(1,n,i)if(a[i]==n){fn=true;break;}
	if(!f1||!fn)
	{
		while(Q--)
		{
			int l=read(),r=read();
			puts(l==1&&r==n?"0":"-1");
		}
		return 0;
	}
	Lg[0]=-1;rep(1,n,i)Lg[i]=Lg[i>>1]+1;
	rep(1,n-1,i)
	{
		mn[0][0][i]=fl[0][i]=min(a[i],a[i+1]);
		mx[0][0][i]=fr[0][i]=max(a[i],a[i+1]);
	}
	
	Init(0);rep(1,34,j)
	{
		rep(1,n-1,i)
		{
			mn[j][0][i]=fl[j][i]=qmn(j-1,fl[j-1][i],fr[j-1][i]-1);
			mx[j][0][i]=fr[j][i]=qmx(j-1,fl[j-1][i],fr[j-1][i]-1);
		}
		Init(j);
	}
//	rep(1,n-1,i)printf("(%d,%d) ",fl[1][i],fr[1][i]);puts("");
	while(Q--)
	{
		int l=read(),r=read();
		if(l==1&&r==n){puts("0");continue;}
		bool flag=0;ll ans=0;
		
		drep(34,0,i)
		{
			int ql=qmn(i,l,r-1),qr=qmx(i,l,r-1);
//			printf("QAQ :: %d %d\n",ql,qr);
			if(!ql){flag=true;break;}
			
			if(ql!=1||qr!=n)l=ql,r=qr,ans|=1ll<<i;
		}
		if(flag||ans>1ll*n*n)puts("-1");
		else printf("%lld\n",ans+1);
	}
	return 0;
}
